    const { todo_id, workflow } = msg as WorkflowGeneratedMessage;
    if (!todo_id || !workflow) return;

    pendingPolls.delete(todo_id);
    applyWorkflowToStore(todo_id, workflow);
    notifyWorkflowGenerated(todo_id);
